from pydantic import BaseModel
from typing import List

class Address(BaseModel):
    street: str
    city: str

class UserProfile(BaseModel):
    name: str
    addresses: List[Address]  # Always require structure

    @field_validator('addresses')
    @classmethod
    def ensure_addresses(cls, v):
        if not v or len(v) == 0:
            return [Address(street='N/A', city='Unknown')]
        return v

