from enum import Enum
from pydantic import BaseModel, field_validator

class Priority(str, Enum):
    low = 'low'
    medium = 'medium'
    high = 'high'

class Task(BaseModel):
    priority: Priority

    @field_validator('priority', mode='before')
    @classmethod
    def strict_enum(cls, v):
        if v not in Priority.__members__:
            raise ValueError(f'Invalid priority: {v}. Must be one of {[e.value for e in Priority]}')
        return v

# Use with strict Instructor mode
task = client.chat.completions.create(
    model='gpt-4o',
    response_model=Task,
    mode='json_schema',
    partial=False
)
